async (params, browser) => {
  // Open Pinterest board
  await browser.open(`${params.board_url}`)

  // Wait for board pins to load
  await browser.waitForSelector('[data-test-id=\'pin\'], [data-test-id=\'pinWrapper\'], div[data-grid-item]', 15000)

  // Let board content fully render
  await browser.wait(3000)

  // Extract board info and pins
  const board_data = await browser.evaluate(`const boardNameEl = document.querySelector('[data-test-id="board-header"] h1, h1, [data-test-id="boardName"]'); const descEl = document.querySelector('[data-test-id="board-description"], [data-test-id="boardDescription"]'); const pinCountEl = document.querySelector('[data-test-id="pin-count"], [data-test-id="board-pin-count"]'); const followerEl = document.querySelector('[data-test-id="follower-count"], [data-test-id="board-follower-count"]'); const creatorEl = document.querySelector('[data-test-id="board-owner-name"] a, [data-test-id="creator-profile-name"] a, [data-test-id="pinner-name"] a'); const pins = []; const pinEls = document.querySelectorAll('[data-test-id="pin"], [data-test-id="pinWrapper"], div[data-grid-item]'); for (let i = 0; i < Math.min(pinEls.length, 25); i++) { const pin = pinEls[i]; const imgEl = pin.querySelector('img'); const linkEl = pin.querySelector('a[href*="/pin/"]'); const titleEl = pin.querySelector('[data-test-id="pinTitle"], [title]') || imgEl; pins.push({ title: titleEl ? (titleEl.getAttribute('title') || titleEl.getAttribute('alt') || titleEl.textContent || '').trim().slice(0, 200) : '', image_url: imgEl ? (imgEl.getAttribute('src') || '') : '', pin_url: linkEl ? 'https://www.pinterest.com' + linkEl.getAttribute('href') : '' }); } return { board_name: boardNameEl ? boardNameEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().slice(0, 500) : '', pin_count: pinCountEl ? pinCountEl.textContent.trim() : '', followers: followerEl ? followerEl.textContent.trim() : '', creator: creatorEl ? creatorEl.textContent.trim() : '', creator_url: creatorEl ? creatorEl.href : '', pins_scraped: pins.length, pins: pins, board_url: window.location.href }`)

  return board_data
}
